module median_filter (
    input [7:0] a,
    input [7:0] b,
    input [7:0] c,
    output reg [7:0] max_value
);

always @(*) begin
    if ((a >= b && a <= c) || (a <= b && a >= c))
        max_value = a;
    else if ((b >= a && b <= c) || (b <= a && b >= c))
        max_value = b;
    else
        max_value = c;
end

endmodule
